mapper.select:
select material_id, park_id, project_id, material_type, file_name, file_url, file_suffix, file_size, sort_order, remark, create_by, create_time from biz_approval_material
and park_id = #{material.parkId} and project_id = #{material.projectId} and material_type = #{material.materialType}
order by sort_order asc, material_id asc

